                      $('#rebateTitle').css({'position':'static','background':'#fff','z-index':'999','box-shadow':'none'})
                    }

                    // 如果垂直滚动, 则取消 'position':'fixed'
                    if (scrollTop) {
                      $('#rebateTitle').css({'position':'static','background':'#fff','z-index':'999','box-shadow':'none'})
                    }

                    // 如果水平滚动 && 垂直滚动
                    if(scrollLeft && scrollTop<102){
                      $('#rebateTitle').css({'left':0+'px','top':101-scrollTop+'px','position':'fixed','background':'#fff','z-index':'999','box-shadow':'0 0 20px #999'})
                    }else if(scrollLeft && scrollTop>102){
                      $('#rebateTitle').css({'left':0+'px','top':'-'+(scrollTop-101)+'px','position':'fixed','background':'#fff','z-index':'999','box-shadow':'0 0 20px #999'})
                    }else if (scrollLeft && !scrollTop) {
                      $('#rebateTitle').css({'left':0+'px','top':'101px','position':'fixed','background':'#fff','z-index':'999','box-shadow':'0 0 20px #999'})
                    }
                  })
                  //========================== 左侧列表滚动悬浮效果 end ==========================

                  // ================ 动态生成左上角列表的 a href连接，并切换左上角的游戏类型文字  start================
                  $('.allLtList a').each(function(){
                    var type = $(this).parents('td').attr('data-type');
                    var name = $(this).text();
                    var href= "/index.ht.do?typeid="+type+"&game_type="+name;
                    $(this).attr('href',href);
                  })
                  // ================ 动态生成左上角列表的 a href连接，并切换左上角的游戏类型文字  end================


                })
              </script>
 </body>
</html>